#!/usr/bin/env python3
"""Build the public Stratos AI website from local lead/automation data with zero model calls."""
from pathlib import Path
import html, json
ROOT = Path(__file__).resolve().parents[1]
leads = json.loads((ROOT/'data'/'leads.json').read_text())
autos = json.loads((ROOT/'data'/'automations.json').read_text())
out = ROOT/'public-site'; out.mkdir(exist_ok=True)
top = sorted(leads, key=lambda l: l['score'], reverse=True)[:6]
auto_cards = ''.join(f"<article><b>{html.escape(a['name'])}</b><p>{html.escape(a['desc'])}</p><span>${a['price']}/mo add-on</span></article>" for a in autos[:6])
lead_cards = ''.join(f"<article><span>{html.escape(l['industry'])} · Score {l['score']}</span><h3>{html.escape(l['business'])}</h3><p>{html.escape(l['angle'])}</p><a href='../{l['demo'].lstrip('/')}'>View concept demo</a></article>" for l in top)
page = f"""<!doctype html><html lang='en'><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>Stratos AI — Boca Raton AI Websites & Automations</title><meta name='description' content='Premium websites and AI automation systems for Boca Raton local businesses.'><style>:root{{--bg:#05060a;--ink:#f7f7fb;--muted:#a8b0c2;--line:#222a3d;--panel:#101523;--accent:#42d3ff;--accent2:#7c83ff}}*{{box-sizing:border-box}}body{{margin:0;background:radial-gradient(circle at 16% 0,rgba(124,131,255,.2),transparent 32%),#05060a;color:var(--ink);font:16px/1.5 Inter,system-ui,sans-serif}}main{{max-width:1160px;margin:auto;padding:28px}}nav{{display:flex;justify-content:space-between;align-items:center;margin-bottom:68px}}nav a,button,.btn{{border:1px solid var(--line);border-radius:999px;padding:11px 15px;color:var(--ink);text-decoration:none;background:#111827}}.hero{{padding:70px 0 44px}}.eyebrow{{color:var(--accent);font-weight:900;letter-spacing:.12em;text-transform:uppercase;font-size:12px}}h1{{font-size:clamp(46px,8vw,92px);line-height:.9;letter-spacing:-.07em;margin:12px 0;max-width:960px}}h2{{font-size:clamp(30px,4vw,54px);line-height:1;margin:0 0 12px}}p{{color:var(--muted);max-width:760px}}.hero p{{font-size:20px}}.grid{{display:grid;grid-template-columns:repeat(auto-fit,minmax(245px,1fr));gap:16px;margin:22px 0 54px}}article,.panel{{border:1px solid var(--line);border-radius:26px;padding:22px;background:linear-gradient(180deg,rgba(255,255,255,.05),rgba(255,255,255,.02));box-shadow:0 24px 70px rgba(0,0,0,.25)}}article span{{color:var(--accent);font-size:13px;font-weight:800}}article a{{color:var(--accent);font-weight:800}}.cta{{display:grid;grid-template-columns:1.2fr .8fr;gap:18px;align-items:center;border:1px solid rgba(66,211,255,.35);border-radius:32px;padding:30px;background:linear-gradient(135deg,rgba(66,211,255,.12),rgba(124,131,255,.12))}}@media(max-width:760px){{.cta{{grid-template-columns:1fr}}nav{{align-items:flex-start;gap:12px;flex-direction:column}}}}</style></head><body><main><nav><b>Stratos AI</b><a href='../index.html'>Command Center</a></nav><section class='hero'><p class='eyebrow'>Boca Raton Growth Systems</p><h1>Premium AI websites that turn local attention into booked revenue.</h1><p>Stratos AI builds conversion-first websites plus AI booking, missed-call recovery, review engines, and follow-up systems for medspas, dental practices, home services, legal, and premium local brands.</p><a class='btn' href='../index.html#war'>Open the command center</a></section><section><p class='eyebrow'>Offers</p><h2>Not generic web design — a lead-capture operating system.</h2><div class='grid'>{auto_cards}</div></section><section><p class='eyebrow'>Concept demos</p><h2>Boca targets already mapped into demo-ready opportunities.</h2><div class='grid'>{lead_cards}</div></section><section class='cta'><div><p class='eyebrow'>Founder workflow</p><h2>Audit → demo → pitch → close room.</h2><p>Every lead gets a focused diagnosis, a specific demo, an outreach pack, and a private proposal room. Repeated generation is handled by local scripts to preserve premium AI quota.</p></div><a class='btn' href='../index.html#usage'>See usage saver system</a></section></main></body></html>"""
(out/'index.html').write_text(page)
print(f"Built public site: {out/'index.html'}")
